#!/usr/bin/env python3
"""Complete Group D Science question generator.
Run: cd C:/Users/core/rrb-exam-prep && python gen_all_complete.py

Adds bilingual (EN/HI) questions to ALL 28 science topic files to reach 100+ each.
"""

import json, os

BASE = "public/data/questions/group-d/general-science"

def load(fname):
    with open(os.path.join(BASE, fname), 'r', encoding='utf-8') as f:
        return json.load(f)

def save(fname, data):
    with open(os.path.join(BASE, fname), 'w', encoding='utf-8') as f:
        json.dump(data, f, indent=2, ensure_ascii=False)
    print(f"  {fname}: {len(data)} questions")

def mq(qid, answer, diff, year, en_q, en_opts, en_exp, hi_q, hi_opts, hi_exp):
    return {
        "id": qid,
        "correctOption": answer,
        "difficulty": diff,
        "sourceYear": year,
        "en": {"question": en_q, "options": list(en_opts), "explanation": en_exp},
        "hi": {"question": hi_q, "options": list(hi_opts), "explanation": hi_exp}
    }

def gen_questions(prefix, start_id, count, question_data_list):
    """Generate sequential questions from data list (each entry is a tuple of question fields)."""
    result = []
    for i, qd in enumerate(question_data_list):
        qid = f"{prefix}-{start_id + i:04d}"
        result.append(mq(qid, *qd))
    return result

